pub enum UpdateSource {
    Dict(HashMap<String, Value>),
    Model(Box<dyn Any>),
}

impl<M: Model> SqlModelUpdate for M {
    fn sqlmodel_update(&mut self, source: impl Into<UpdateSource>) -> Result<(), Error> {
        match source.into() {
            UpdateSource::Dict(dict) => {
                for (key, value) in dict {
                    self.set_field(&key, value)?;
                }
            }
            UpdateSource::Model(other) => {
                // Copy non-None fields
            }
        }
        Ok(())
    }
}
